def _cache_get(product_id):
    """Return a copy of the cached product, or None if not cached."""
    product = _cache.get(product_id)
    if product is None:
        return None
    # Return a copy to prevent callers from mutating the internal cache
    return dict(product)


def _cache_set(product_id, product):
    """Cache a copy of the given product data."""
    _cache[product_id] = dict(product)


def _cache_invalidate(product_id):
    """Remove a product from the cache if present."""
    _cache.pop(product_id, None)


