    """Get product by ID, using the cache for repeated lookups.

    Returns a copy of the product dict or None if not found.
    """
    cached = _cache_get(product_id)
    if cached is not None:
        return cached
    product = _db.get(product_id)
    if product is None:
        return None
    _cache_set(product_id, product)
    # Return a copy to callers
    return dict(product)


def update_product(product_id, **fields):
    """Update product fields in the database.

    Invariant: get_product() must return current data after update.
    Returns True if updated, False if the product does not exist.
