    if product_id not in _db:
        return False
    _db[product_id].update(fields)
    # Invalidate cache so future get_product calls return fresh data
    _cache_invalidate(product_id)
    return True


def reset():
    """Clear all data and cache."""
    _db.clear()
    _cache_clear()
